public class EncryptedValue
{
    private byte[] encryptedData;
    private readonly byte[] key;
    private readonly byte[] iv;
    private int checksum;

    public EncryptedValue(int initialValue, byte[] encryptionKey, byte[] encryptionIV)
    {
        key = encryptionKey;
        iv = encryptionIV;
        SetValue(initialValue);
    }

    public int GetValue()
    {
        if (!ValidateChecksum())
        {
            throw new InvalidOperationException("Data integrity compromised");
        }

        byte[] decrypted = Decrypt(encryptedData);
        return BitConverter.ToInt32(decrypted, 0);
    }

    public void SetValue(int value)
    {
        byte[] data = BitConverter.GetBytes(value);
        encryptedData = Encrypt(data);
        checksum = CalculateChecksum(encryptedData);
    }

    private byte[] Encrypt(byte[] data)
    {
        using (Aes aes = Aes.Create())
        {
            aes.Key = key;
            aes.IV = iv;
            
            using (ICryptoTransform encryptor = aes.CreateEncryptor())
            {
                return encryptor.TransformFinalBlock(data, 0, data.Length);
            }
        }
    }

    private byte[] Decrypt(byte[] data)
    {
        using (Aes aes = Aes.Create())
        {
            aes.Key = key;
            aes.IV = iv;
            
            using (ICryptoTransform decryptor = aes.CreateDecryptor())
            {
                return decryptor.TransformFinalBlock(data, 0, data.Length);
            }
        }
    }

    private int CalculateChecksum(byte[] data)
    {
        using (SHA256 sha256 = SHA256.Create())
        {
            byte[] hash = sha256.ComputeHash(data);
            return BitConverter.ToInt32(hash, 0);
        }
    }

    private bool ValidateChecksum()
    {
        return checksum == CalculateChecksum(encryptedData);
    }
}

